PAYLOAD
base64 -d "$TMP_DIR/payload.b64" > "$TMP_DIR/payload.tar.gz"
tar -xzf "$TMP_DIR/payload.tar.gz" -C "$TMP_DIR"
SRC_DIR="$TMP_DIR/aster-browser-theme-zoom-context-ui-fixed"
[[ -d "$SRC_DIR" ]] || die "Extracted source directory not found"

rm -rf "$APP_DIR"
cp -a "$SRC_DIR" "$APP_DIR"
msg "Bundled app extracted to $APP_DIR"

if [[ ! -x "$VENV_DIR/bin/python" ]]; then
  msg "Creating virtual environment"
  "$PYTHON_BIN" -m venv "$VENV_DIR"
fi

msg "Installing Python dependencies (first run can take a bit)"
"$VENV_DIR/bin/python" -m pip install -r "$APP_DIR/requirements-lock.txt"

cat > "$LAUNCHER" <<EOF2
#!/usr/bin/env bash
set -euo pipefail
exec "$VENV_DIR/bin/python" "$APP_DIR/run_aster.py" "\$@"
EOF2
chmod +x "$LAUNCHER"
msg "Launcher created at $LAUNCHER"

cat > "$DESKTOP_FILE" <<EOF2
[Desktop Entry]
Type=Application
Name=Aster Browser
Exec=$LAUNCHER %U
Terminal=false
Categories=Network;WebBrowser;
StartupNotify=true
EOF2
msg "Desktop entry created at $DESKTOP_FILE"

if [[ "$NO_RUN" -eq 0 ]]; then
  msg "Starting Aster Browser..."
  exec "$LAUNCHER"
else
  msg "Done. Launch later with: $LAUNCHER"
fi
